export async function getDecisionRecordForWorkspace(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
  decisionInput: string;
}): Promise<{ id: RecordId<"decision", string>; summary: string; status: string }> {
