import { logError } from "../../http/observability";
import type { ChatToolDeps } from "./types";

async function resolveProjectWithRetry(
  deps: ChatToolDeps,
  workspaceRecord: RecordId<"workspace", string>,
  projectInput: string,
): Promise<RecordId<"project", string>> {
  try {
    return await resolveWorkspaceProjectRecord({
      surreal: deps.surreal,
      workspaceRecord,
      projectInput,
    });
  } catch {
    // Parallel tool execution race: project may have been created in the same
    // LLM step but its has_project edge isn't committed yet. Retry once.
    await new Promise((r) => setTimeout(r, 500));
    return await resolveWorkspaceProjectRecord({
      surreal: deps.surreal,
      workspaceRecord,
      projectInput,
    });
  }
}

